import{_ as s,c as a,o as e,a4 as i}from"./chunks/framework.BOW58p_D.js";const m=JSON.parse('{"title":"高於1.16.5的版本","description":"","frontmatter":{},"headers":[],"relativePath":"mc_server/forge/hv.md","filePath":"mc_server/forge/hv.md","lastUpdated":1714220644000}'),t={name:"mc_server/forge/hv.md"},n=i(`<h1 id="高於1-16-5的版本" tabindex="-1">高於1.16.5的版本 <a class="header-anchor" href="#高於1-16-5的版本" aria-label="Permalink to &quot;高於1.16.5的版本&quot;">​</a></h1><p>適用於<code>1.17.1</code> ~ 目前的最新版</p><h2 id="下載" tabindex="-1">下載 <a class="header-anchor" href="#下載" aria-label="Permalink to &quot;下載&quot;">​</a></h2><p>前往<a href="https://files.minecraftforge.net/net/minecraftforge/forge/" target="_blank" rel="noreferrer">forge</a>官網下載要安裝的版本。</p><p><img src="https://i.imgur.com/vCnNXUj.png" alt="Imgur"></p><p>左側可以選擇版本，右側可以選擇要下載甚麼版本(最新版或推薦版本)。 按下<code>installer</code>之後，可能會有5秒的廣告，5秒後可以按右上角的<code>skip</code>跳過。</p><p>我使用<code>1.20.4</code>來示範。</p><hr><p>將下載的jar檔案點兩下打開，選擇<code>Install server</code>，並按下面的三個點蘭指定安裝位置</p><p><img src="https://i.imgur.com/O2B7Clq.png" alt="Imgur"></p><p>完成後按下<code>OK</code>開始安裝</p><p>安裝完成後會跳出這個通知</p><p><img src="https://i.imgur.com/kf1gFBg.png" alt="Imgur"></p><h2 id="啟動伺服器" tabindex="-1">啟動伺服器 <a class="header-anchor" href="#啟動伺服器" aria-label="Permalink to &quot;啟動伺服器&quot;">​</a></h2><p>在你選擇安裝伺服器的資料夾裡，多出了這些文件:</p><p><img src="https://i.imgur.com/cK2KYzi.png" alt="Imgur"></p><p>你不需要完全知道所有檔案和資料夾是用來幹嘛的，你只需要知道:</p><ul><li><strong><code>run.bat</code></strong> : 用來啟動伺服器。</li><li><strong><code>user_jvm_args.txt</code></strong> : 用來設定伺服器的記憶體大小。</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>如果你的作業系統不是 <strong>Linux</strong> 或 <strong>macOS</strong> ，可以將<code>run.sh</code>刪除。</p></div><p>如果不想要讓伺服器開啟圖形化介面占用資源，可以編輯<code>run.bat</code>，在</p><p><code>java @libraries/net/minecraftforge/forge/1.20.4-49.0.49/win_args.txt %*</code> 的尾部加入<code>nogui</code>。 例如:</p><div class="language-bat vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bat</span><pre class="shiki shiki-themes github-light github-dark has-focused-lines vp-code"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">@echo</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> off</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">java -jar forge-1.20.4-49.0.49-shim.jar --onlyCheckJava</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> %ERRORLEVEL% </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">NEQ</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    echo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    echo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> If you&#39;re struggling to fix the error above, ask for help on the forums or Discord mentioned in the readme.</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    goto</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> :</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">exit</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"></span>
<span class="line has-focus"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">java </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">@</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">libraries/net/minecraftforge/forge/1.20.4-49.0.49/win_args.txt </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">%*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> nogui</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">exit</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">pause</span></span></code></pre></div><p>對<code>run.bat</code>點兩下，啟動伺服器。 如果成功的話，會在記錄檔的最後一行跳出</p><p><strong><code>You need to agree to the EULA in order to run the server. Go to eula.txt for more info.</code></strong></p><p>打開資料夾內的<code>eula.txt</code> 將<code>eula=false</code>的<code>false</code>改成<code>true</code>，然後再啟動一次伺服器(再次開啟run.bat)。</p><p>當記錄檔跳出<code>Done (37.431s)! For help, type &quot;help&quot;</code>時，代表伺服器已經成功開啟。</p><div class="warning custom-block"><p class="custom-block-title">注意</p><p>在遊玩伺服器的期間，不要把cmd關閉，一旦cmd被關閉，伺服器就會關閉。</p></div><h2 id="修改伺服器記憶體" tabindex="-1">修改伺服器記憶體 <a class="header-anchor" href="#修改伺服器記憶體" aria-label="Permalink to &quot;修改伺服器記憶體&quot;">​</a></h2><p>打開<code>user_jvm_args.txt</code></p><p>在最後一行，把<code>#</code>拿掉，從<code># -Xmx4G</code>變成<code>-Xmx4G</code>。</p><p>你可以使用**M (代表MB)<strong>和</strong>G (代表GB)**兩個單位來設定記憶體大小</p><p><code>-Xmx</code>是用來設定<strong>可使用的最大</strong>記憶體大小</p><p><code>-Xms</code>是用來設定<strong>應使用的最小</strong>記憶體大小</p><p>但其實只要設定<code>Xmx</code>的量就可以了</p><div class="warning custom-block"><p class="custom-block-title">注意</p><p>修改完成後記得儲存。</p></div><h2 id="停止伺服器" tabindex="-1">停止伺服器 <a class="header-anchor" href="#停止伺服器" aria-label="Permalink to &quot;停止伺服器&quot;">​</a></h2><p>打開伺服器的cmd，輸入<code>stop</code>，等待一段時間，伺服器就成功關閉了。</p>`,37),o=[n];function p(r,l,c,h,d,k){return e(),a("div",null,o)}const u=s(t,[["render",p]]);export{m as __pageData,u as default};
